chart.options:
chart: {
  height: 350,
  type: 'line',
  zoom: {
    enabled: false,
  },
},
dataLabels: {
  enabled: false,
},
title: {
  text: 'Monthly Temperature Anomaly',
  align: 'left',
},
subtitle: {
  text: 'Months below the baseline draw in a different color',
  align: 'left',
},
yaxis: {
  labels: {
    formatter: function (val) {
      return val.toFixed(1) + '°C'
    }
  }
},
xaxis: {
  categories: [
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ],
},
stroke: {
  width: 5,
  curve: "monotoneCubic"
},
plotOptions: {
  line: {
    colors: {
      threshold: 0,
      colorAboveThreshold: '#008FFB',
      colorBelowThreshold: '#FF4560',
    },
  },
}
